Rules.InvariantScript:
Set(
    gblProjectSidebarItemCurrent,
    ThisItem
);
If(
    ThisItem.Category="Job Entry",
    Navigate(
        'Windows Screen',
        ScreenTransition.None
    ),
    ThisItem.Category="Window Measurement",
    Set(
        gblRecordWindowMeasurement_Tech,
        LookUp(
            colCdsWindowMeasurements,
            'Window Measurement' = gblRecordJobEntryCurrent_.'Measurement (Tech)'.'Window Measurement'
        )
    );
    // check if Job Completed status
    If(
        gblRecordJobCurrent.Completed = gblOptionSets.Job.CompletedJob.No,
        Set(
            gblRecordWindowChoice,
            LookUp(
                colCdsWindowChoices,
                'Window Choice' = gblRecordJobEntryCurrent_.'Window Choice'.'Window Choice'
            )
        );
        Set(
            gblRecordWindowMeasurement_Sales,
            LookUp(
                colCdsWindowMeasurements,
                'Window Measurement' = gblRecordJobEntryCurrent_.'Measurement (Sales)'.'Window Measurement'
            )
        );
        Clear(colMeasureWidth);
        Clear(colMeasureHeight);
        Clear(colMeasureJambDepth);
        Clear(colMeasureMaxProjection);
        Clear(colMeasureSoffitDepth);
        Clear(colMeasureWallThickness);
        With(
            {
                varWidthMin: Value(gblRecordWindowChoice.'Min Width'),
                varWidthRange: Value(gblRecordWindowChoice.'Max Width') - Value(gblRecordWindowChoice.'Min Width'),
                varHeightMin: Value(gblRecordWindowChoice.'Min Height'),
                varHeightRange: Value(gblRecordWindowChoice.'Max Height') - Value(gblRecordWindowChoice.'Min Height'),
                varJambDepthMin: Value(gblRecordWindowChoice.'Min Jamb Depth'),
                varJambDepthRange: Value(gblRecordWindowChoice.'Max Jamb Depth') - Value(gblRecordWindowChoice.'Min Jamb Depth'),
                varMaxProjectionMin: Value(gblRecordWindowChoice.'Min Max Projection'),
                varMaxProjectionRange: Value(gblRecordWindowChoice.'Max Max Projection') - Value(gblRecordWindowChoice.'Min Max Projection'),
                varSoffitDepthMin: Value(gblRecordWindowChoice.'Min Soffit Depth'),
                varSoffitDepthRange: Value(gblRecordWindowChoice.'Max Soffit Depth') - Value(gblRecordWindowChoice.'Min Soffit Depth'),
                varWallThicknessMin: Value(gblRecordWindowChoice.'Min Wall Thickness'),
                varWallThicknessRange: Value(gblRecordWindowChoice.'Max Wall Thickness') - Value(gblRecordWindowChoice.'Min Wall Thickness')
            },
            Concurrent(
                ForAll(
                    Sequence(varWidthRange+1),
                    Collect(
                        colMeasureWidth,
                        {tblValue: ThisRecord.Value + varWidthMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varHeightRange+1),
                    Collect(
                        colMeasureHeight,
                        {tblValue: ThisRecord.Value + varHeightMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varJambDepthRange+1),
                    Collect(
                        colMeasureJambDepth,
                        {tblValue: ThisRecord.Value + varJambDepthMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varMaxProjectionRange+1),
                    Collect(
                        colMeasureMaxProjection,
                        {tblValue: ThisRecord.Value + varMaxProjectionMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varSoffitDepthRange+1),
                    Collect(
                        colMeasureSoffitDepth,
                        {tblValue: ThisRecord.Value + varSoffitDepthMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varWallThicknessRange+1),
                    Collect(
                        colMeasureWallThickness,
                        {tblValue: ThisRecord.Value + varWallThicknessMin - 1}
                    )
                )
            )

        );
        Concurrent(
            Set(
                gblMeasurementWidthWhole,
                RoundDown(
                    If(
                        gblRecordWindowMeasurement_Tech.Width = 0,
                        gblRecordWindowMeasurement_Sales.Width,
                        gblRecordWindowMeasurement_Tech.Width
                    ),
                    0
                )
            ),
            Set(
                gblMeasurementHeightWhole,
                RoundDown(
                    If(
                        gblRecordWindowMeasurement_Tech.Height = 0,
                        gblRecordWindowMeasurement_Sales.Height,
                        gblRecordWindowMeasurement_Tech.Height
                    ),
                    0
                )
            ),
            Set(
                gblMeasurementJambDepthWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Jamb Depth',
                    0
                )
            ),
            Set(
                gblMeasurementMaxProjectionWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Max Projection',
                    0
                )
            ),
            Set(
                gblMeasurementSoffitDepthWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Soffit Depth',
                    0
                )
            ),
            Set(
                gblMeasurementWallThicknessWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Wall Thickness',
                    0
                )
            ),
            Set(
                gblMeasurementWidthFraction,
                With(
                    {
                        varWidth: If(
                            gblRecordWindowMeasurement_Tech.Width = 0,
                            gblRecordWindowMeasurement_Sales.Width,
                            gblRecordWindowMeasurement_Tech.Width
                        )
                    },
                    varWidth - RoundDown(
                        varWidth,
                        0
                    )
                )
            ),
            Set(
                gblMeasurementHeightFraction,
                With(
                    {
                        varHeight: If(
                            gblRecordWindowMeasurement_Tech.Height = 0,
                            gblRecordWindowMeasurement_Sales.Height,
                            gblRecordWindowMeasurement_Tech.Height
                        )
                    },
                    varHeight - RoundDown(
                        varHeight,
                        0
                    )
                )
            ),
            Set(
                gblMeasurementJambDepthFraction,
                gblRecordWindowMeasurement_Tech.'Jamb Depth' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Jamb Depth',
                    0
                )
            ),
            Set(
                gblMeasurementMaxProjectionFraction,
                gblRecordWindowMeasurement_Tech.'Max Projection' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Max Projection',
                    0
                )
            ),
            Set(
                gblMeasurementSoffitDepthFraction,
                gblRecordWindowMeasurement_Tech.'Soffit Depth' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Soffit Depth',
                    0
                )
            ),
            Set(
                gblMeasurementWallThicknessFraction,
                gblRecordWindowMeasurement_Tech.'Wall Thickness' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Wall Thickness',
                    0
                )
            )
        );
        Set(
            gblMeasurementMaxUI,
            gblRecordWindowChoice.'Max UI'
        );
    );
    // reset screen
    Reset(gal_Windows_Select);
    // next screen
    If(
        gblRecordJobCurrent.Completed = gblOptionSets.Job.CompletedJob.No,

        Navigate(
            'Measure Window Screen',
            ScreenTransition.Fade
        ),
        Navigate(
            'Measurements Screen',
            ScreenTransition.None
        )
    )
)

With(
    {
        varRecordWindowMeasurement: If(
            ThisItem.Category="Window Measurement",
            LookUp(
                colCdsWindowMeasurements,
                'Window Measurement'=ThisItem.ID
            ),
            Blank()
        )
    },
    Or(
        !IsBlank(varRecordWindowMeasurement.'Window Mull'.'Sequence Number'),
        !IsBlank(varRecordWindowMeasurement.'Lead Test: Exterior Result')
    )
)

Blank()
//TODO
/*
If(
    gblRecordJobEntryCurrent_.'Job Entry' = ThisItem.'Job Entry' And locShowWindowActionsMenu,
    UpdateContext({
        locShowWindowActionsMenu: false
    }),
    UpdateContext({
        locShowWindowActionsMenu: true
    })
);
Set(
    gblRecordJobEntryCurrent_,
    ThisItem
);
*/

With(
    {
        varType: "colCdsWindowMeasurements",
        varRecordRef: ThisItem.'Window Measurement'
    },
    // update window measurement
    UpdateIf(
        colCdsWindowMeasurements,
        colCdsWindowMeasurements[@'Window Measurement'] = varRecordRef,
        {Notes: Self.Text}
    );
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
// save local data

IfError( // This line of code is added to hide the errors

If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsWindowMeasurements,
        "localCdsWindowMeasurements"
    )
)
,Blank())  // This line of code is added to hide the errors

;

With(
    {
        varFirstRecord: First(
            Filter(
                colCdsWindowMeasurements,
                colCdsWindowMeasurements[@'Job Entry'].'Job Entry' = gblRecordJobEntryCurrent_.'Job Entry'
            )
        )
    },
    IfError(
        Coalesce(
            Substitute(
                If(
                    varFirstRecord.'Exception?' = 'Exception? (Window Measurements)'.Yes,
                    Concatenate(
                        varFirstRecord.Name,
                        " (EXCEPTION)"
                    ),
                    varFirstRecord.Name
                ),
                ".000",
                Char(34)
            ),
            varFirstRecord.Name
        ),
        varFirstRecord.Name
    )
)
